+"use client";
+
+import { useRef, useEffect, useState } from "react";
+import { motion, useScroll, useTransform, useSpring } from "framer-motion";
+import {
+  Clock,
+  Sparkles,
+  Terminal,
+  Play,
+  ChevronDown,
+  MessageSquare,
+  Code2,
+  Zap,
+} from "lucide-react";
+import { cn } from "@/lib/utils";
+import { useCountUp, easings } from "@/hooks/useCountUp";
+
+interface EnhancedHeroProps {
+  duration: string;
+  messageCount: number;
+  linesWritten: number;
+  toolCalls: number;
+}
+
+// Floating orb component
+function FloatingOrb({
+  className,
+  delay = 0,
+}: {
+  className?: string;
+  delay?: number;
+}) {
+  return (
+    <motion.div
+      initial={{ opacity: 0, scale: 0 }}
+      animate={{ opacity: 1, scale: 1 }}
+      transition={{ delay, duration: 1, ease: "easeOut" }}
+      className={cn("absolute rounded-full blur-3xl", className)}
+    >
+      <motion.div
+        animate={{
+          y: [0, -20, 0],
+          x: [0, 10, 0],
+          scale: [1, 1.1, 1],
+        }}
+        transition={{
+          duration: 8,
+          repeat: Infinity,
+          ease: "easeInOut",
+          delay,
+        }}
+        className="w-full h-full rounded-full"
+      />
+    </motion.div>
+  );
+}
+
+// Animated grid background
+function GridBackground() {
+  return (
+    <div className="absolute inset-0 overflow-hidden">
+      {/* Base gradient */}
+      <div className="absolute inset-0 bg-gradient-to-b from-violet-50 via-white to-white dark:from-zinc-900 dark:via-zinc-950 dark:to-zinc-950" />
+
+      {/* Grid pattern */}
+      <div
+        className="absolute inset-0 opacity-[0.015] dark:opacity-[0.03]"
+        style={{
+          backgroundImage: `linear-gradient(to right, currentColor 1px, transparent 1px),
+                           linear-gradient(to bottom, currentColor 1px, transparent 1px)`,
+          backgroundSize: "80px 80px",
+        }}
+      />
+
+      {/* Radial gradient overlay */}
+      <div className="absolute inset-0 bg-[radial-gradient(ellipse_at_center,_transparent_0%,_var(--tw-gradient-from)_100%)] from-white dark:from-zinc-950" />
+    </div>
+  );
+}
+
+// Mini stat badge
+function StatBadge({
+  icon: Icon,
+  value,
+  label,
+  delay,
+  inView,
+}: {
+  icon: typeof Clock;
+  value: number;
+  label: string;
+  delay: number;
+  inView: boolean;
+}) {
+  const count = useCountUp({
+    end: value,
+    duration: 2500,
+    delay: delay * 1000,
+    enabled: inView,
+  });
+
+  return (
+    <motion.div
+      initial={{ opacity: 0, y: 20 }}
+      animate={inView ? { opacity: 1, y: 0 } : {}}
+      transition={{ delay, duration: 0.5 }}
+      className={cn(
+        "flex items-center gap-2 px-4 py-2 rounded-full",
+        "bg-white/60 dark:bg-zinc-800/60",
+        "backdrop-blur-md",
+        "border border-zinc-200/50 dark:border-zinc-700/50",
+        "shadow-sm"
+      )}
+    >
+      <Icon className="w-4 h-4 text-violet-500" />
+      <span className="font-semibold text-zinc-900 dark:text-zinc-100 tabular-nums">
+        {count.toLocaleString()}
+      </span>
+      <span className="text-sm text-zinc-500 dark:text-zinc-400">{label}</span>
+    </motion.div>
+  );
+}
+
+export function EnhancedHero({
+  duration,
+  messageCount,
+  linesWritten,
+  toolCalls,
+}: EnhancedHeroProps) {
+  const containerRef = useRef<HTMLDivElement>(null);
+  const [inView, setInView] = useState(false);
+
+  useEffect(() => {
+    const timer = setTimeout(() => setInView(true), 100);
+    return () => clearTimeout(timer);
+  }, []);
+
+  const { scrollYProgress } = useScroll({
+    target: containerRef,
+    offset: ["start start", "end start"],
