+          )}
+          title={section.title}
+        />
+      ))}
+    </div>
+  );
+}
+
+// Enhanced section header
+function SectionHeader({
+  section,
+  index,
+  isExpanded,
+  onToggle,
+  messageCount,
+}: {
+  section: TranscriptSection;
+  index: number;
+  isExpanded: boolean;
+  onToggle: () => void;
+  messageCount: number;
